import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"魔剑【昂巴尔】","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/2.C级/魔剑【昂巴尔】.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/2.C级/魔剑【昂巴尔】.md"}'),p={name:"4.资源分区/7.物品与装备/2.武器/近战武器/2.C级/魔剑【昂巴尔】.md"};function d(_,a,l,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"魔剑【昂巴尔】",tabindex:"-1"},[s("魔剑【昂巴尔】 "),e("a",{class:"header-anchor",href:"#魔剑【昂巴尔】","aria-label":'Permalink to "魔剑【昂巴尔】"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新秩序000")])])],-1),o('<h1 id="魔剑【昂巴尔】-1" tabindex="-1">魔剑【昂巴尔】 <a class="header-anchor" href="#魔剑【昂巴尔】-1" aria-label="Permalink to &quot;魔剑【昂巴尔】&quot;">​</a></h1><p>魔剑【昂巴尔】<br> C+1000<br> 11L 3体积  破甲2<br> 魔幻本质<br> 这是一把武器伤害11 3体积 力量需求3  破甲2 攻击造成【精神伤害】</p><p>噬身之蛇盟主所赐予的魔剑“昂巴尔”，与剑帝·莱恩哈特的噬岩者成对，由于曾经的使用者与该武器契合度过高，此武器外观变成了一把浑身赤红并且散发着不详气息的单手剑。使用者在拥有这把剑后便会一直听到曾经的使用者呢喃以及飘渺的注视。</p><p>‘那个银发女人给了我这把剑，似乎相性太好了以至于这把剑因为我发生了一些微小的变化。’</p><p>当使用者使用武器进行攻击时，魔剑会尝试强化自己的使用者并且帮助使用者强化本次攻击，使用者在攻击前投掷一个不受任何加成的机运骰，当出目为6-10时，使用者可以使用一个移动动作引发昂巴尔的潜在力量，使下一次攻击获得【9加骰】，并且被攻击者似乎能听到异世界魔人的低语，逐渐沉溺在获得力量的虚幻魔境之中，攻击者将此次攻击的成功数转化为魅惑点数，对方以标准对抗豁免。</p><p>当你每次使用昂巴尔攻击一个敌对目标时，持有者通过引发曾经异世界魔人的力量来尝试扭曲被攻击者的心智并且支配对方，对方以意志豁免对抗你对对方造成伤害的成功数，若对抗成功，则无效果，若对抗失败则暂时不触发效果，使用者必须在本回合以一个迅捷动作将昂巴尔归入鞘中，其特殊的音波会回荡在敌对目标耳边并且使对方在一定时间内无法分辨现实与虚幻的边界。</p><p>魔剑的使用者可以在被支配者的回合开始时对其下达指令，该命令必须明确且必须在能力范围内的具体行动，若对方选择违抗指令，则会从昂巴尔上爆发出血色的能量，并且使对方获得4点精神易伤，仅生效一次。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const m=r(p,[["render",d]]);export{f as __pageData,m as default};
